query:
-- Deletar presenças registradas para a aula número 1 (01/03)
DELETE FROM presencas WHERE aulaNumero = 1;

-- Deletar a aula 01/03
DELETE FROM aulas WHERE data = '01/03';

-- Renumerar as aulas restantes (decrementar numero em 1)
UPDATE aulas SET numero = numero - 1 WHERE numero > 1 ORDER BY numero ASC;

